1	//! 稳定符号 ID 系统
2	//!
3	//! 基于 blake3 指纹的稳定符号标识符，格式为：
4	//! `language::relative_path::kind::name::fingerprint`
5	//!
6	//! 其中 fingerprint 为 `name + path + language + kind` 串联后
7	//! blake3 哈希的前 8 字符（前 4 字节）。
8	
9	use serde::{Deserialize, Serialize};
10	
11	/// 稳定符号 ID
12	///
13	/// 由语言、路径、符号类型、名称和 blake3 指纹组成。
14	/// 指纹确保即使符号重命名或移动后也能通过原始属性查找到。
15	#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
16	pub struct StableSymbolId {
17	    /// 编程语言（rust, typescript, java 等）
18	    pub language: String,
19	    /// 相对于项目根目录的文件路径
20	    pub relative_path: String,
21	    /// 符号类型
22	    pub kind: String,
23	    /// 符号名称
24	    pub name: String,
25	    /// blake3 指纹（8 字符十六进制）
26	    pub fingerprint: String,
27	}
28	
29	impl StableSymbolId {
30	    /// 创建新的稳定符号 ID
31	    ///
32	    /// 自动计算 blake3 指纹。
33	    pub fn new(language: &str, relative_path: &str, kind: &str, name: &str) -> Self {
34	        let fingerprint = Self::compute_fingerprint(language, relative_path, kind, name);
35	        Self {
36	            language: language.to_string(),
37	            relative_path: relative_path.to_string(),
38	            kind: kind.to_string(),
39	            name: name.to_string(),
40	            fingerprint,
41	        }
42	    }
43	
44	    /// 计算 blake3 指纹
45	    ///
