1	//! Rust 语言解析器
2	//!
3	//! 使用 tree-sitter-rust grammar 解析 .rs 文件，
4	//! 提取函数、结构体、trait、枚举、方法等符号定义，
5	//! 以及函数调用和 use 导入语句。
6	
7	use std::path::Path;
8	use std::sync::Mutex;
9	
10	use codeconnect_core::error::CodeConnectError;
11	use codeconnect_core::symbol_id::StableSymbolId;
12	use codeconnect_core::types::{
13	    CallSite, CallType, Import, ImportResolution, SourceLocation, Symbol, SymbolKind,
14	};
15	use streaming_iterator::StreamingIterator;
16	use tree_sitter::{Parser, Query, QueryCursor, Tree};
17	
18	use crate::query_loader::load_rust_queries;
19	use crate::r#trait::LanguageParser;
20	
21	/// Rust 语言解析器
22	///
23	/// 包装了 tree-sitter-rust grammar 和一个 `Mutex<Parser>`，
24	/// 确保并发调用时的线程安全。
25	pub struct RustParser {
26	    /// tree-sitter 解析器实例（Mutex 因为 Parser 不是 Sync）
27	    parser: Mutex<Parser>,
28	}
29	
30	impl RustParser {
31	    /// 创建新的 Rust 解析器
32	    pub fn new() -> Self {
33	        let mut parser = Parser::new();
34	        // tree-sitter 0.24: language() 函数返回 Language 引用
35	        parser
36	            .set_language(&tree_sitter_rust::language())
37	            .expect("加载 Rust tree-sitter grammar 失败");
38	        Self {
39	            parser: Mutex::new(parser),
40	        }
41	    }
42	
43	    /// 将 tree-sitter 节点转为源码位置（0-based → 1-based）
44	    fn node_to_location(&self, node: tree_sitter::Node) -> SourceLocation {
45	        let start = node.start_position();
46	        let end = node.end_position();
47	        SourceLocation {
48	            file_path: String::new(), // 由外部调用者填充
49	            line: start.row as u64 + 1,
50	            column: start.column as u64 + 1,
51	            end_line: end.row as u64 + 1,
52	            end_column: end.column as u64 + 1,
53	        }
54	    }
55	
56	    /// 获取节点的源码文本（UTF-8 安全）
57	    fn node_text<'a>(&self, node: tree_sitter::Node, source: &'a str) -> &'a str {
58	        node.utf8_text(source.as_bytes()).unwrap_or("")
59	    }
60	}
61	
62	impl Default for RustParser {
63	    fn default() -> Self {
64	        Self::new()
65	    }
66	}
67	
68	impl LanguageParser for RustParser {
69	    fn language(&self) -> &'static str {
70	        "rust"
71	    }
72	
73	    fn file_extensions(&self) -> &[&str] {
74	        &["rs"]
75	    }
76	
77	    fn parse(&self, source: &str) -> Result<Tree, CodeConnectError> {
78	        let mut parser = self.parser.lock().map_err(|e| CodeConnectError::Parse {
79	            file: Path::new("").to_path_buf(),
80	            message: format!("获取解析器锁失败: {}", e),
81	        })?;
82	        parser
83	            .parse(source, None)
84	            .ok_or_else(|| CodeConnectError::Parse {
85	                file: Path::new("").to_path_buf(),
86	                message: "Rust 源码解析失败，可能包含语法错误".to_string(),
87	            })
88	    }
89	
90	    fn extract_symbols(&self, tree: &Tree, source: &str, file_path: &Path) -> Vec<Symbol> {
91	        let queries = load_rust_queries();
92	        let file_path_str = file_path.to_string_lossy().to_string();
93	        let mut results = Vec::new();
94	
95	        let query = match Query::new(&tree_sitter_rust::language(), &queries.symbols) {
96	            Ok(q) => q,
97	            Err(_) => return results,
98	        };
99	
100	        let mut cursor = QueryCursor::new();
101	        // tree-sitter 0.24: matches() 返回 StreamingIterator，不是标准 Iterator
102	        // 需要导入 streaming_iterator::StreamingIterator 使用 next()/advance()+get()
103	        let mut matches = cursor.matches(&query, tree.root_node(), source.as_bytes());
104	
105	        while let Some(m) = matches.next() {
106	            let mut name = String::new();
107	            let mut parent = String::new();
108	            let mut kind = SymbolKind::Unknown("unknown".to_string());
109	            let mut location = SourceLocation {
110	                file_path: file_path_str.clone(),
111	                line: 0,
112	                column: 0,
113	                end_line: 0,
114	                end_column: 0,
115	            };
116	
117	            for capture in m.captures {
118	                let node = capture.node;
119	                let capture_name = query.capture_names()[capture.index as usize];
120	
121	                match capture_name {
122	                    "symbol.name" => {
123	                        name = self.node_text(node, source).to_string();
124	                    }
125	                    "symbol.function" => {
126	                        kind = SymbolKind::Function;
127	                        location = self.node_to_location(node);
128	                    }
129	                    "symbol.method" => {
130	                        kind = SymbolKind::Method;
131	                        location = self.node_to_location(node);
132	                    }
133	                    "symbol.struct" => {
134	                        kind = SymbolKind::Struct;
135	                        location = self.node_to_location(node);
136	                    }
137	                    "symbol.trait" => {
138	                        kind = SymbolKind::Trait;
139	                        location = self.node_to_location(node);
140	                    }
141	                    "symbol.enum" => {
142	                        kind = SymbolKind::Enum;
143	                        location = self.node_to_location(node);
144	                    }
145	                    "symbol.type_alias" => {
146	                        kind = SymbolKind::TypeAlias;
147	                        location = self.node_to_location(node);
148	                    }
149	                    "symbol.macro" => {
150	                        kind = SymbolKind::Macro;
151	                        location = self.node_to_location(node);
152	                    }
153	                    "symbol.module" => {
154	                        kind = SymbolKind::Module;
155	                        location = self.node_to_location(node);
156	                    }
157	                    "symbol.variable" => {
158	                        kind = SymbolKind::Variable;
159	                        location = self.node_to_location(node);
160	                    }
161	                    "symbol.field" => {
162	                        kind = SymbolKind::Field;
163	                        location = self.node_to_location(node);
164	                    }
165	                    "symbol.parent" => {
166	                        parent = self.node_text(node, source).to_string();
167	                    }
168	                    _ => {}
169	                }
170	            }
171	
172	            if name.is_empty() {
173	                continue;
174	            }
175	
176	            let kind_str = match &kind {
177	                SymbolKind::Function => "function",
178	                SymbolKind::Method => "method",
179	                SymbolKind::Struct => "struct",
180	                SymbolKind::Trait => "trait",
181	                SymbolKind::Enum => "enum",
182	                SymbolKind::TypeAlias => "type_alias",
183	                SymbolKind::Macro => "macro",
184	                SymbolKind::Module => "module",
185	                SymbolKind::Variable => "variable",
186	                SymbolKind::Field => "field",
187	                _ => "unknown",
188	            };
189	
190	            let id = StableSymbolId::new("rust", &file_path_str, kind_str, &name);
191	
192	            // Rust 顶层符号默认是私有的，以大写字母开头的符号大概率是公开 API
193	            let is_exported = name.chars().next().map_or(false, |c| c.is_uppercase())
194	                || matches!(
195	                    kind,
196	                    SymbolKind::Function
197	                        | SymbolKind::Struct
198	                        | SymbolKind::Trait
199	                        | SymbolKind::Enum
200	                );
201	
202	            let parent_id = if parent.is_empty() {
203	                None
204	            } else {
205	                Some(StableSymbolId::new("rust", &file_path_str, "struct", &parent).to_string())
206	            };
207	
208	            let modifiers = if is_exported {
209	                vec!["pub".to_string()]
210	            } else {
211	                vec!["private".to_string()]
212	            };
213	
214	            results.push(Symbol {
215	                id: id.to_string(),
216	                name,
217	                kind,
218	                location,
219	                signature: None,
220	                doc_comment: None,
221	                parent_id,
222	                modifiers,
223	                is_exported,
224	                complexity: None,
225	            });
226	        }
227	
228	        results
229	    }
230	
231	    fn extract_calls(&self, tree: &Tree, source: &str, file_path: &Path) -> Vec<CallSite> {
232	        let queries = load_rust_queries();
233	        let file_path_str = file_path.to_string_lossy().to_string();
234	        let mut results = Vec::new();
235	
236	        let query = match Query::new(&tree_sitter_rust::language(), &queries.calls) {
237	            Ok(q) => q,
238	            Err(_) => return results,
239	        };
240	
241	        let mut cursor = QueryCursor::new();
242	        let mut matches = cursor.matches(&query, tree.root_node(), source.as_bytes());
243	
244	        while let Some(m) = matches.next() {
245	            let mut callee_name = String::new();
246	            let mut call_type = CallType::Direct;
247	            let mut location = SourceLocation {
248	                file_path: file_path_str.clone(),
249	                line: 0,
250	                column: 0,
251	                end_line: 0,
252	                end_column: 0,
253	            };
254	
255	            for capture in m.captures {
256	                let node = capture.node;
257	                let capture_name = query.capture_names()[capture.index as usize];
258	
259	                match capture_name {
260	                    "call.name" => {
261	                        callee_name = self.node_text(node, source).to_string();
262	                    }
263	                    "call" => {
264	                        location = self.node_to_location(node);
265	                    }
266	                    "call.method" => {
267	                        call_type = CallType::Virtual; // Rust 方法调用可能通过 trait 动态分发
268	                        location = self.node_to_location(node);
269	                    }
270	                    "call.macro" => {
271	                        call_type = CallType::MacroExpansion;
272	                        location = self.node_to_location(node);
273	                    }
274	                    _ => {}
275	                }
276	            }
277	
278	            if !callee_name.is_empty() && location.line > 0 {
279	                results.push(CallSite {
280	                    caller_id: String::new(), // 由外部调用者上下文补充
281	                    callee_name,
282	                    location,
283	                    call_type,
284	                    confidence: 0.9,
285	                });
286	            }
287	        }
288	
289	        results
290	    }
291	
292	    fn extract_imports(&self, tree: &Tree, source: &str, file_path: &Path) -> Vec<Import> {
293	        let queries = load_rust_queries();
294	        let file_path_str = file_path.to_string_lossy().to_string();
295	        let mut results = Vec::new();
296	
297	        let query = match Query::new(&tree_sitter_rust::language(), &queries.imports) {
298	            Ok(q) => q,
299	            Err(_) => return results,
300	        };
301	
302	        let mut cursor = QueryCursor::new();
303	        let mut matches = cursor.matches(&query, tree.root_node(), source.as_bytes());
304	
305	        while let Some(m) = matches.next() {
306	            let mut import_path = String::new();
307	            let mut alias = None;
308	            let mut import_line: u64 = 0;
309	
310	            for capture in m.captures {
311	                let node = capture.node;
312	                let capture_name = query.capture_names()[capture.index as usize];
313	
314	                match capture_name {
315	                    "import.path" => {
316	                        import_path = self.node_text(node, source).to_string();
317	                    }
318	                    "import.name" => {
319	                        alias = Some(self.node_text(node, source).to_string());
320	                    }
321	                    "import" | "import.extern" => {
322	                        import_line = node.start_position().row as u64 + 1;
323	                    }
324	                    _ => {}
325	                }
326	            }
327	
328	            // 对于 extern crate（仅 alias 无 import_path），使用 alias 作为路径
329	            let path = if import_path.is_empty() {
330	                alias.clone().unwrap_or_default()
331	            } else {
332	                import_path
333	            };
334	
335	            if !path.is_empty() {
336	                results.push(Import {
337	                    file_path: file_path_str.clone(),
338	                    import_path: path,
339	                    alias,
340	                    line: import_line,
341	                    resolution: ImportResolution::Unresolved,
342	                });
343	            }
344	        }
345	
346	        results
347	    }
348	
349	    fn infer_package(&self, file_path: &Path, _source: &str) -> Option<String> {
350	        // Rust 项目：从文件路径的目录结构中推断 crate 名
351	        // 遍历路径组件，跳过 "src" 目录，取第一个正常目录名
352	        let components: Vec<_> = file_path.components().collect();
353	        for component in components.iter().rev() {
354	            if let std::path::Component::Normal(name) = component {
355	                let name_str = name.to_str().unwrap_or("");
356	                if name_str == "src" {
357	                    continue;
358	                }
359	                if !name_str.is_empty() {
360	                    return Some(name_str.to_string());
361	                }
362	            }
363	        }
364	        None
365	    }
366	}
