    /// 调试测试：打印 AST 结构和查询匹配结果
    #[test]
    fn test_debug_query() {
        let source = "fn main() {\n    println!(\"Hello\");\n}\n";
        let parser = RustParser::new();
        let tree = parser.parse(source).expect("解析失败");

        // 打印 AST
        println!("=== AST ===");
        let root = tree.root_node();
        print_tree(&root, source, 0);

        // 尝试编译查询
        let queries = load_rust_queries();
        println!("\n=== 查询内容 ===");
        println!("{}", queries.symbols);

        // 尝试直接遍历子节点
        println!("\n=== 根节点直接子节点 ===");
        let mut cursor = root.walk();
        for child in root.children(&mut cursor) {
            println!("  kind={}, text={:?}", child.kind(), child.utf8_text(source.as_bytes()).unwrap_or("?"));
        }

        // 尝试用特定的 query pattern
        let query_str = "(function_item name: (identifier) @name) @func";
        let query = tree_sitter::Query::new(&parser.language, query_str).unwrap();
        let mut qc = tree_sitter::QueryCursor::new();
        let mut matches = qc.matches(&query, root, source.as_bytes());
        println!("\n=== 简化查询结果 (function_item) ===");
        while let Some(m) = matches.next() {
            for cap in m.captures {
                let text = cap.node.utf8_text(source.as_bytes()).unwrap_or("?");
                let name = query.capture_names()[cap.index as usize];
                println!("  capture '{}': {:?}", name, text);
            }
        }
    }

    fn print_tree(node: &tree_sitter::Node, source: &str, depth: usize) {
        let indent = "  ".repeat(depth);
        let text = node.utf8_text(source.as_bytes()).unwrap_or("?");
        if text.len() > 80 {
            println!("{}{}: {:?}...", indent, node.kind(), &text[..80]);
        } else {
            println!("{}{}: {:?}", indent, node.kind(), text);
        }
        let mut cursor = node.walk();
        for child in node.children(&mut cursor) {
            print_tree(&child, source, depth + 1);
        }
    }

    #[test]
