        let source = r#"
fn main() {
    println!("Hello, world!");
}
"#;
        let (tree, parser) = parse_source(source);
        let symbols = parser.extract_symbols(&tree, source, Path::new("test.rs"));
        assert!(!symbols.is_empty(), "应提取到至少一个符号");
